const webhook = $('Webhook').first().json;
const post = $input.first().json;

// C4: Verify webhook authentication via body secret
const secret = webhook.body?._secret || webhook._secret || '';
const expectedSecret = 'YOUR_CROSSPOST_SECRET';
if (expectedSecret && secret !== expectedSecret) {
  throw new Error('Unauthorized: invalid crosspost secret');
}

if (!post || !post.slug) {
  throw new Error('Post not found: ' + (webhook.body?.slug || 'unknown'));
}
if (post.frontmatter?.draft === true) {
  throw new Error('Skipping draft post: ' + post.slug);
}

const canonical = 'https://YOUR_BLOG_DOMAIN/posts/' + post.slug + '/';
let imageUrl = '';
if (post.frontmatter?.image) {
  imageUrl = post.frontmatter.image.startsWith('http')
    ? post.frontmatter.image
    : 'https://YOUR_BLOG_DOMAIN' + post.frontmatter.image;
}

const tags = (post.frontmatter?.tags || []).slice(0, 8);
const categories = (post.frontmatter?.categories || []);
const fullBody = post.body || '';
const truncBody = fullBody.length > 5000 ? fullBody.substring(0, 5000) + '\n\n[...truncated for AI prompt...]' : fullBody;

return [{
  json: {
    slug: post.slug,
    lang: post.lang || 'en',
    title: post.frontmatter?.title || post.slug,
    description: post.frontmatter?.description || '',
    date: post.frontmatter?.date || '',
    categories: categories,
    tags: tags,
    body: fullBody,
    body_truncated: truncBody,
    canonical_url: canonical,
    image_url: imageUrl,
    source: 'aethon-insights'
  }
}];

const post = $('Validate Post').first().json;
const sheetRows = $('Read Tracker').all().map(i => i.json);
const existing = sheetRows.find(r => r.slug === post.slug && r.source === 'aethon-insights');

// Platform API keys — fill in to enable auto-posting
const config = {
  devto_api_key: '',
  hashnode_token: '',
  hashnode_publication_id: '',
};

// Track what's already been posted
let already = {};
if (existing) {
  ['linkedin','devto','hashnode','substack','twitter','facebook','reddit'].forEach(p => {
    if (existing[p + '_status'] === 'published') already[p] = true;
  });
}

return [{
  json: {
    ...post,
    config,
    already_posted: already,
    is_retry: !!existing,
    do_linkedin: !already.linkedin,
    do_devto: !already.devto && !!config.devto_api_key,
    do_hashnode: !already.hashnode && !!config.hashnode_token && !!config.hashnode_publication_id,
  }
}];

const post = $input.first().json;

const systemPrompt = `You are a world-class B2B content marketing strategist for Aethon Automation, an AI and business automation company. Your goal: MAXIMIZE engagement, reach, and thought leadership on every platform.

BRAND VOICE: Professional yet approachable. Data-driven. Forward-thinking. Authoritative on AI and automation.

CRITICAL: Each platform's content must feel NATIVE — not a copy-paste. Adapt tone, length, structure, and style for each audience.

Return ONLY valid JSON (no markdown fences) with this exact structure:
{
  "linkedin": { "text": "string (max 3000 chars)" },
  "twitter_thread": { "tweets": ["string (max 270 chars each)", ...] },
  "devto": { "title": "string", "tags": ["string (max 4, lowercase, no spaces)"], "body": "string (full markdown article)" },
  "hashnode": { "title": "string", "subtitle": "string", "tags": [{"slug":"string","name":"string"}], "body": "string (full markdown article)" },
  "facebook": { "text": "string (max 500 chars)" },
  "reddit": { "title": "string", "body": "string (value-first, non-promotional)", "subreddits": ["string"] },
  "substack": { "title": "string", "subtitle": "string", "body": "string (newsletter-style markdown)" }
}`;

const userPrompt = `Generate high-impact social media content for this Aethon Automation blog post:

TITLE: ${post.title}
DESCRIPTION: ${post.description}
URL: ${post.canonical_url}
TAGS: ${(post.tags || []).join(', ')}
CATEGORIES: ${(post.categories || []).join(', ')}

ARTICLE CONTENT:
${post.body_truncated}

=== PLATFORM REQUIREMENTS ===

1. LINKEDIN (B2B powerhouse — max 3000 chars):
   - Open with a BOLD pattern-interrupt hook
   - Use line breaks for mobile readability
   - 3-5 key takeaways as bullet points with emojis
   - End with engagement question
   - CTA: "Read the full breakdown on Aethon Insights"
   - 6-8 hashtags including #AethonAutomation #AIAutomation
   - DO NOT include the URL in the text

2. TWITTER/X THREAD (5-7 tweets, max 270 chars each):
   - Tweet 1: Hook + end with thread emoji
   - Tweets 2-5: One insight per tweet
   - Tweet 6: CTA + article link
   - Tweet 7: Follow CTA with hashtags

3. DEV.TO (developer community — technical focus):
   - Developer-focused title
   - 4 tags (lowercase, no spaces)
   - Full markdown article
   - Practical, code examples where relevant

4. HASHNODE (developer blogging — thought leadership):
   - Compelling title + subtitle
   - 5 tags as {slug, name} objects
   - Full markdown article

5. FACEBOOK (max 500 chars):
   - Relatable question or surprising fact
   - Conversational tone, 2-3 emojis
   - 3-5 hashtags

6. REDDIT (community value — zero promotion):
   - Informative title
   - Lead with VALUE, 3-5 key insights
   - Mention article link naturally at end
   - Suggest 3 subreddits

7. SUBSTACK (newsletter style):
   - Newsletter-friendly title + subtitle
   - Warm intro, full content, personal closing`;

const requestBody = {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  response_format: { type: 'json_object' },
  temperature: 0.75,
  max_tokens: 14000
};

return [{
  json: {
    ...post,
    openai_request: requestBody
  }
}];

const prev = $('Build AI Prompt').first().json;
const config = $('Platform Config').first().json.config;
const openaiResp = $input.first().json;

let ai;
try {
  const raw = openaiResp.choices[0].message.content;
  ai = JSON.parse(raw);
} catch(e) {
  ai = {
    linkedin: { text: prev.title + '\n\n' + prev.description + '\n\nRead more on Aethon Insights:\n\n#AethonAutomation #AIAutomation #BusinessAutomation' },
    twitter_thread: { tweets: [prev.title + ' thread', prev.description, 'Full article: ' + prev.canonical_url, 'Follow @AethonAutomation for more'] },
    devto: { title: prev.title, tags: prev.tags.slice(0,4).map(t=>t.toLowerCase().replace(/[^a-z0-9]/g,'')), body: prev.body },
    hashnode: { title: prev.title, subtitle: prev.description, tags: prev.tags.map(t=>({slug:t.toLowerCase().replace(/\s/g,'-'),name:t})), body: prev.body },
    facebook: { text: prev.description + '\n\n' + prev.canonical_url + '\n\n#AethonAutomation' },
    reddit: { title: prev.title, body: prev.description + '\n\nFull article: ' + prev.canonical_url, subreddits: ['artificial','automation','smallbusiness'] },
    substack: { title: prev.title, subtitle: prev.description, body: prev.body }
  };
}

// Build Dev.to request body
const devtoBody = JSON.stringify({
  article: {
    title: ai.devto?.title || prev.title,
    body_markdown: (ai.devto?.body || prev.body) + '\n\n---\n\n*Originally published on [Aethon Insights](' + prev.canonical_url + ')*',
    canonical_url: prev.canonical_url,
    tags: (ai.devto?.tags || prev.tags).slice(0,4).map(t => String(t).toLowerCase().replace(/[^a-z0-9]/g,'')),
    published: true
  }
});

// Build Hashnode request body
const hnTags = (ai.hashnode?.tags || []).slice(0,5).map(t => {
  if (typeof t === 'string') return { slug: t.toLowerCase().replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,''), name: t };
  return t;
});
const hashnodeBody = JSON.stringify({
  query: `mutation PublishPost($input: PublishPostInput!) {
    publishPost(input: $input) {
      post { url slug title }
    }
  }`,
  variables: {
    input: {
      title: ai.hashnode?.title || prev.title,
      subtitle: ai.hashnode?.subtitle || prev.description,
      contentMarkdown: (ai.hashnode?.body || prev.body),
      tags: hnTags,
      publicationId: config.hashnode_publication_id || 'NOT_CONFIGURED',
      originalArticleURL: prev.canonical_url
    }
  }
});

// Build Twitter thread text for email
const tweets = ai.twitter_thread?.tweets || [];
const twitterThreadText = tweets.map((t, i) => `${i+1}/${tweets.length}) ${t}`).join('\n\n');

// Build manual platform content for email
const manualPlatforms = [];

if (tweets.length > 0) {
  manualPlatforms.push({
    name: 'Twitter/X Thread', icon: 'twitter',
    content: twitterThreadText,
    instructions: 'Post as a thread. Copy each numbered tweet as a separate reply.'
  });
}

if (ai.facebook?.text) {
  manualPlatforms.push({
    name: 'Facebook', icon: 'facebook',
    content: ai.facebook.text + '\n\n' + prev.canonical_url,
    instructions: 'Post on Aethon Automation Facebook page. Add link in comment for better reach.'
  });
}

if (ai.reddit?.title) {
  manualPlatforms.push({
    name: 'Reddit', icon: 'reddit',
    content: '**Title:** ' + ai.reddit.title + '\n\n' + ai.reddit.body,
    instructions: 'Suggested subreddits: ' + (ai.reddit.subreddits || []).map(s => 'r/' + s).join(', ')
  });
}

if (ai.substack?.body) {
  manualPlatforms.push({
    name: 'Substack Newsletter', icon: 'substack',
    content: '**Title:** ' + (ai.substack?.title || prev.title) + '\n**Subtitle:** ' + (ai.substack?.subtitle || prev.description),
    instructions: 'Paste into Substack editor. Set canonical URL to: ' + prev.canonical_url,
    full_body: ai.substack.body
  });
}

return [{
  json: {
    ...prev,
    ai,
    config,
    linkedin_text: ai.linkedin?.text || (prev.title + '\n\n' + prev.description + '\n\n#AethonAutomation'),
    devto_body: devtoBody,
    hashnode_body: hashnodeBody,
    devto_api_key: config.devto_api_key || '',
    hashnode_token: config.hashnode_token || '',
    manual_platforms: manualPlatforms,
    twitter_thread: twitterThreadText,
    do_linkedin: prev.do_linkedin,
    do_devto: prev.do_devto,
    do_hashnode: prev.do_hashnode,
    already_posted: prev.already_posted || {}
  }
}];

const post = $('Prepare All Posts').first().json;
const already = post.already_posted || {};

function getResult(nodeName, platform) {
  if (already[platform]) return { status: 'already_posted', url: '' };
  try {
    const data = $(nodeName).first().json;
    if (data?.error || data?.statusCode >= 400 || data?.serviceErrorCode || data?.errors) {
      const msg = data.message || data.error || data.errors?.[0]?.message || 'API error';
      return { status: 'failed', url: '', error: msg };
    }
    const url = data?.postUrl || data?.activity || data?.url ||
                data?.data?.publishPost?.post?.url ||
                (data?.id ? 'https://dev.to/api/articles/' + data.id : '') || '';
    return { status: 'published', url };
  } catch(e) {
    return { status: 'not_attempted', url: '', error: String(e).substring(0, 100) };
  }
}

const linkedin = post.do_linkedin ? getResult('Post to LinkedIn', 'linkedin') : { status: 'skipped', url: '' };
const devto = post.do_devto ? getResult('Post to Dev.to', 'devto') : { status: post.config?.devto_api_key ? 'skipped' : 'not_configured', url: '' };
const hashnode = post.do_hashnode ? getResult('Post to Hashnode', 'hashnode') : { status: post.config?.hashnode_token ? 'skipped' : 'not_configured', url: '' };

const twitter = already.twitter ? { status: 'already_posted' } : { status: 'content_ready' };
const facebook = already.facebook ? { status: 'already_posted' } : { status: 'content_ready' };
const reddit = already.reddit ? { status: 'already_posted' } : { status: 'content_ready' };
const substack = already.substack ? { status: 'already_posted' } : { status: 'content_ready' };

const allResults = { linkedin, devto, hashnode, twitter, facebook, reddit, substack };

const published = Object.values(allResults).filter(r => r.status === 'published').length;
const failed = Object.values(allResults).filter(r => r.status === 'failed').length;
const ready = Object.values(allResults).filter(r => r.status === 'content_ready').length;
const notConfigured = Object.values(allResults).filter(r => r.status === 'not_configured').length;

const errors = Object.entries(allResults)
  .filter(([_, r]) => r.status === 'failed' && r.error)
  .map(([name, r]) => name + ': ' + r.error);

return [{
  json: {
    slug: post.slug,
    title: post.title,
    date: post.date,
    canonical_url: post.canonical_url,
    image_url: post.image_url || '',
    source: 'aethon-insights',
    crossposted_at: new Date().toISOString().split('T')[0],
    linkedin_status: linkedin.status,
    linkedin_url: linkedin.url || '',
    devto_status: devto.status,
    devto_url: devto.url || '',
    hashnode_status: hashnode.status,
    hashnode_url: hashnode.url || '',
    twitter_status: twitter.status,
    facebook_status: facebook.status,
    reddit_status: reddit.status,
    substack_status: substack.status,
    notes: errors.join('; '),
    published_count: published,
    failed_count: failed,
    content_ready_count: ready,
    not_configured_count: notConfigured,
    total_platforms: 7,
    has_failures: failed > 0,
    manual_platforms: post.manual_platforms || [],
    twitter_thread: post.twitter_thread || '',
    body: post.body || '',
    ai: post.ai || {}
  }
}];

